-- Remove development seed data from production.
-- Seeds 006 and 013 inserted fake users, plugins, versions, categories and
-- dependencies that are only useful for local development.
-- All seed rows use fixed UUIDs prefixed with a1/b3/c2/d4/e5 000000-…

-- 1. Plugin dependencies (013)
DELETE FROM plugin_dependencies WHERE id IN (
    'e5000000-0000-0000-0000-000000000001',
    'e5000000-0000-0000-0000-000000000002',
    'e5000000-0000-0000-0000-000000000003',
    'e5000000-0000-0000-0000-000000000004',
    'e5000000-0000-0000-0000-000000000005'
);

